<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Snake Game</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #333;
            font-family: 'Arial', sans-serif;
        }

        canvas {
            display: block;
            width: 400px;
            height: 400px;
            background-color: #444;
            border-radius: 10px;
            box-shadow: 0 0 20px rgba(255,255,255,0.5);
        }

        .controls {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            background-color: #555;
            padding: 15px;
            border-radius: 10px;
            box-shadow: 0 0 20px rgba(255,255,255,0.5);
        }

        .controls button {
            margin: 8px;
            padding: 10px 20px;
            background-color: #4CAF50;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            font-size: 16px;
        }

        .controls button:hover {
            background-color: #45a049;
        }

        .score-display {
            margin-top: 20px;
            font-weight: bold;
            color: #2c3e50;
        }
    </style>
</head>
<body>
    <div class="controls">
        <button id="start">Start Game</button>
        <button id="pause">Pause</button>
        <button id="reset">Reset</button>
    </div>

    <canvas id="snake" width="400" height="400"></canvas>
    <div class="score-display">Score: 0</div>

    <script>
        // Game state interface
        window.game = {
            w, h,                 // board size in cells (>= 10)
            reset(),              // new game: snake length >= 3, alive, score 0
            tick(),               // advance exactly one step
            setDir('up'|'down'|'left'|'right'),   // queue a turn (ignore 180° reversals),
            setFood(x, y),        // place the food (used by grading; also redraw)
            snake(): array of [x,y], HEAD FIRST,
            food(): [x,y],
            alive(): boolean,
            score(): number
        };

        // Initialize game state
        window.game.reset = function() {
            game.snake = [[10, 10]];
            game.food = [20, 20];
            game.alive = true;
            game.score = 0;
        };

        window.game.tick = function() {
            if (!game.alive) return;

            // Move snake one step in current direction
            const dir = game.setDir(game.snake[0]);
            let newHead = [game.snake[0][dir] + 1, game.snake[0][dir]];

            // Check for collision with walls or food
            if (newHead[0] < 0 || newHead[0] >= game.w || 
                newHead[1] < 0 || newHead[1] >= game.h) {
                return; // Wall collision
            }

            if (game.food && newHead[0] === game.food[0] && newHead[1] === game.food[1]) {
                // Eating food: grow snake and increment score
                game.snake.push(newHead);
                game.score++;
                // Place new food on free cell
                const newFood = [game.w - 10, game.h - 10]; // Example placement
                if (newFood[0] >= 0 && newFood[0] < game.w && 
                    newFood[1] >= 0 && newFood[1] < game.h) {
                    game.food = newFood;
                }
            } else {
                // Move snake without eating
                game.snake.push(newHead);
            }

            // Draw board (simplified for visibility)
            drawBoard();
        };

        window.game.setDir = function(dir) {
            if (!game.alive || game.snake.length < 3) return;

            const head = game.snake[0];
            const body = game.snake.slice(1);

            // Ignore 180° reversal (turn left while moving right)
            if ((dir === 'up' && dir === 'right') ||
                (dir === 'down' && dir === 'left') ||
                (dir === 'left' && dir === 'down') ||
                (dir === 'right' && dir === 'up')) {
                return; // Ignore reversal
            }

            // Determine movement direction based on current heading and desired turn
            let moveDir = game.setDir(dir);
            if ((moveDir === 'left' && dir === 'down') ||
                (moveDir === 'right' && dir === 'up')) {
                moveDir = 'left';
            }

            // Move snake one step in new direction
            const [newHeadX, newHeadY] = [head[0], head[1]];
            if (dir === 'down') newHeadY += 1;
            else if (dir === 'up') newHeadY -= 1;
            else if (dir === 'left') newHeadX -= 1;
            else if (dir === 'right') newHeadX += 1;

            // Check collision with walls or food
            if (newHead[0] < 0 || newHead[0] >= game.w || 
                newHead[1] < 0 || newHead[1] >= game.h) {
                return; // Wall collision
            }

            if (game.food && newHead[0] === game.food[0] && newHead[1] === game.food[1]) {
                // Eating food: grow snake and increment score
                body.push([newHeadX, newHeadY]);
                game.score++;
                // Place new food on free cell
                const newFood = [game.w - 10, game.h - 10]; // Example placement
                if (newFood[0] >= 0 && newFood[0] < game.w && 
                    newFood[1] >= 0 && newFood[1] < game.h) {
                    game.food = newFood;
                }
            } else {
                // Move snake without eating
                body.push([newHeadX, newHeadY]);
            }

            // Draw board (simplified for visibility)
            drawBoard();
        };

        window.game.setFood = function(x, y) {
            game.food = [x, y];
            drawBoard();
        };

        window.game.snake = function() {
            return [[10, 10]];
        };

        window.game.food = function() {
            return [20, 20];
        };

        window.game.alive = function() {
            return true;
        };

        window.game.score = function() {
            return game.score;
        };
    </script>
</body>
</html>
